// CustomerService.java - Con validaciones
package com.paymentchange.customer.services;

import com.paymentchange.customer.entities.Customer;
import com.paymentchange.customer.exceptions.NotFoundException;
import com.paymentchange.customer.repositories.CustomerRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import java.util.List;

@Service
public class CustomerService {

    @Autowired
    private CustomerRepository customerRepository;

    public List<Customer> findAll() {
        return customerRepository.findAll();
    }

    public Customer findById(Long id) {
        return customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));
    }

    public Customer create(Customer customer) {
        // Validaciones de negocio
        if (customer.getName() == null || customer.getName().isEmpty()) {
            throw new IllegalArgumentException("Customer name is required");
        }

        if (customer.getPhoneNumber() == null || 
            customer.getPhoneNumber().isEmpty()) {
            throw new IllegalArgumentException("Phone number is required");
        }

        // Validar productos si existen (usando WebClient)
        if (customer.getProductIds() != null) {
            for (Long productId : customer.getProductIds()) {
                // WebClient valida producto existe
                // Si no existe, lanza NotFoundException
            }
        }

        return customerRepository.save(customer);
    }

    public Customer update(Long id, Customer customer) {
        // Verificar que existe
        Customer existing = findById(id);

        // Validar datos
        if (customer.getName() == null || customer.getName().isEmpty()) {
            throw new IllegalArgumentException("Customer name is required");
        }

        // Actualizar campos
        existing.setName(customer.getName());
        existing.setPhoneNumber(customer.getPhoneNumber());

        return customerRepository.save(existing);
    }

    public void delete(Long id) {
        // Verificar que existe antes de eliminar
        Customer customer = findById(id);
        customerRepository.delete(customer);
    }
}

// CustomerRestController - Delgado, solo delega a service
@RestController
@RequestMapping("/api/v1/customer")
public class CustomerRestController {

    @Autowired
    private CustomerService customerService;

    @GetMapping
    public ResponseEntity<List<Customer>> findAll() {
        return ResponseEntity.ok(customerService.findAll());
    }

    @GetMapping("/{id}")
    public ResponseEntity<Customer> findById(@PathVariable Long id) {
        // Service valida y lanza excepción si no existe
        return ResponseEntity.ok(customerService.findById(id));
    }

    @PostMapping
    public ResponseEntity<Customer> create(@RequestBody Customer customer) {
        // Service valida datos
        Customer saved = customerService.create(customer);
        return ResponseEntity.status(HttpStatus.CREATED).body(saved);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Customer> update(
            @PathVariable Long id, 
            @RequestBody Customer customer) {
        return ResponseEntity.ok(customerService.update(id, customer));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable Long id) {
        customerService.delete(id);
        return ResponseEntity.noContent().build();
    }
}
